const body = $input.item.json.body || $input.item.json;

const task_done     = body.task_done     || null;
const task_progress = body.task_progress || null;
const time_needed   = body.time_needed   || null;
const blockers      = body.blockers      || null;
const from          = body.from          || null;
const flow_token    = body.flow_token    || null;

let taskIdFromToken   = null;
let memberIdFromToken = null;
if (flow_token && flow_token.includes('_')) {
  const parts = flow_token.split('_');
  taskIdFromToken   = parts[0];
  memberIdFromToken = parts.slice(1).join('_');
}

if (!task_done) {
  return { json: { skip: true, reason: 'missing_task_done' } };
}

let noteText = null;
if (task_done === 'no') {
  const parts = [];
  if (task_progress) parts.push('📍 فين في التاسك: ' + task_progress);
  if (time_needed)   parts.push('⏳ وقت كمان: ' + time_needed);
  if (blockers)      parts.push('🚧 Blockers: ' + blockers);
  noteText = parts.join(' | ') || 'لم يتم تحديد تفاصيل';
}

return {
  json: {
    skip: false,
    from: from ? from.replace(/\D/g, '') : null,
    task_done,
    task_progress,
    time_needed,
    blockers,
    noteText,
    taskIdFromToken,
    memberIdFromToken,
    receivedAt: Date.now()
  }
};

function fromFV(v) {
  if (v == null) return null;
  if ('stringValue' in v) return v.stringValue;
  if ('integerValue' in v) return parseInt(v.integerValue);
  if ('doubleValue' in v) return parseFloat(v.doubleValue);
  if ('booleanValue' in v) return v.booleanValue;
  if ('nullValue' in v) return null;
  if ('timestampValue' in v) return v.timestampValue;
  if ('arrayValue' in v) return (v.arrayValue.values || []).map(fromFV);
  if ('mapValue' in v) return fromFF(v.mapValue.fields || {});
  return null;
}
function fromFF(fields) {
  const o = {};
  for (const k in fields) o[k] = fromFV(fields[k]);
  return o;
}
function parseDoc(doc) {
  const id = doc.name.split('/').pop();
  return { id, ...fromFF(doc.fields || {}) };
}
function toFV(v) {
  if (v === null || v === undefined) return { nullValue: null };
  if (typeof v === 'string') return { stringValue: v };
  if (typeof v === 'boolean') return { booleanValue: v };
  if (typeof v === 'number') {
    if (Number.isInteger(v)) return { integerValue: String(v) };
    return { doubleValue: v };
  }
  if (Array.isArray(v)) return { arrayValue: { values: v.map(toFV) } };
  if (typeof v === 'object') {
    const fields = {};
    for (const k in v) fields[k] = toFV(v[k]);
    return { mapValue: { fields } };
  }
  return { nullValue: null };
}

const parsed = $('Parse Flow Data').first().json;
const allItems = $input.all();

let members = [];
let tasks   = [];

for (let i = 0; i < allItems.length; i++) {
  const docs = allItems[i].json.documents || [];
  if (!docs.length) continue;
  const path = docs[0].name || '';
  if (path.includes('/members/')) members = docs.map(parseDoc);
  if (path.includes('/tasks/'))   tasks   = docs.map(parseDoc);
}

// لاقي العضو
let matchedMember = null;
if (parsed.memberIdFromToken) {
  for (let i = 0; i < members.length; i++) {
    if (members[i].id === parsed.memberIdFromToken) { matchedMember = members[i]; break; }
  }
}
if (!matchedMember && parsed.from) {
  const fromDigits = parsed.from;
  for (let i = 0; i < members.length; i++) {
    const mp = (members[i].phone || '').replace(/\D/g, '');
    if (mp && (mp === fromDigits || mp.endsWith(fromDigits) || fromDigits.endsWith(mp))) {
      matchedMember = members[i]; break;
    }
  }
}
if (!matchedMember) return { json: { found: false, reason: 'member_not_found' } };

// لاقي التاسك
let targetTask = null;
if (parsed.taskIdFromToken) {
  for (let i = 0; i < tasks.length; i++) {
    if (tasks[i].id === parsed.taskIdFromToken) { targetTask = tasks[i]; break; }
  }
}
if (!targetTask) {
  const memberTasks = [];
  for (let i = 0; i < tasks.length; i++) {
    const t = tasks[i];
    if (t.status !== 'inprogress') continue;
    const assignees = (Array.isArray(t.assignees) && t.assignees.length) ? t.assignees : (t.assignee ? [t.assignee] : []);
    let found = false;
    for (let j = 0; j < assignees.length; j++) { if (assignees[j] === matchedMember.id) { found = true; break; } }
    if (found) memberTasks.push(t);
  }
  memberTasks.sort(function(a, b) {
    const aT = a.deadline ? new Date(a.deadline).getTime() : 0;
    const bT = b.deadline ? new Date(b.deadline).getTime() : 0;
    return aT - bT;
  });
  targetTask = memberTasks[0] || null;
}
if (!targetTask) return { json: { found: false, reason: 'task_not_found' } };

// بناء الـ log entry
const currentLog = Array.isArray(targetTask.activityLog) ? targetTask.activityLog : [];
const nowMs = Date.now();
const isDone = parsed.task_done === 'yes';

const newLogEntry = {
  source: 'whatsapp_flow',
  type:   isDone ? 'task_completed' : 'progress_update',
  text:   isDone ? 'أكد إنه خلص التاسك عن طريق الفلو' : (parsed.noteText || 'لم يتم تحديد تفاصيل'),
  timestamp:  nowMs,
  memberId:   matchedMember.id,
  memberName: matchedMember.name
};

const updatedLog = currentLog.slice();
updatedLog.push(newLogEntry);

// لو خلص → حدّث status + activityLog
// لو لسه → حدّث activityLog بس
const updatedFields = {};
const maskFields    = ['activityLog'];
updatedFields.activityLog = toFV(updatedLog);
if (isDone) {
  updatedFields.status = toFV('done');
  maskFields.push('status');
}

return {
  json: {
    found:      true,
    taskId:     targetTask.id,
    taskName:   targetTask.name,
    memberId:   matchedMember.id,
    memberName: matchedMember.name,
    task_done:  parsed.task_done,
    isDone,
    maskFields,
    bodyStr: JSON.stringify({ fields: updatedFields })
  }
};
